const DEFAULT_SKILLS = [
  { name: 'Python', type: 'match' }, { name: 'ML Systems', type: 'partial' },
  { name: 'SQL', type: 'partial' }, { name: 'NLP', type: 'miss' },
  { name: 'PyTorch', type: 'miss' }, { name: 'Docker', type: 'partial' },
];

function getSkillsForTitle(title) {
  for (const key of Object.keys(TITLE_SKILLS)) {
    if (title.includes(key) || key.includes(title.split(' ').slice(-2).join(' '))) {
      return TITLE_SKILLS[key];
    }
  }
  // Fuzzy fallback
  const titleLower = title.toLowerCase();
  if (titleLower.includes('nlp')) return TITLE_SKILLS['NLP Engineer'];
  if (titleLower.includes('recommendation')) return TITLE_SKILLS['Recommendation Systems Engineer'];
  if (titleLower.includes('search')) return TITLE_SKILLS['Search Engineer'];
  if (titleLower.includes('ai research')) return TITLE_SKILLS['AI Research Engineer'];
  if (titleLower.includes('vision')) return TITLE_SKILLS['Computer Vision Engineer'];
  if (titleLower.includes('data scientist')) return TITLE_SKILLS['Data Scientist'];
  if (titleLower.includes('lead ai')) return TITLE_SKILLS['Lead AI Engineer'];
  if (titleLower.includes('senior ai')) return TITLE_SKILLS['Senior AI Engineer'];
  if (titleLower.includes('specialist')) return TITLE_SKILLS['AI Specialist'];
  if (titleLower.includes('backend')) return TITLE_SKILLS['Backend Engineer'];
  if (titleLower.includes('data engineer')) return TITLE_SKILLS['Data Engineer'];
  return DEFAULT_SKILLS;
}

// Parse initials from candidate ID e.g. CAND_0018499 → rank-based letter pairs
function getInitials(rank, title) {
  const words = title.split(' ').filter(w => w.length > 1);
  if (words.length >= 2) return (words[0][0] + words[1][0]).toUpperCase();
  if (words.length === 1) return words[0].slice(0, 2).toUpperCase();
  return 'ML';
}

// Map raw 0-1 score → three sub-scores for UI display
function deriveScores(rawScore, coreSkillsCount) {
  const base = Math.round(rawScore * 100);
  const skillBonus = Math.min(10, coreSkillsCount * 2);
  const semanticScore = Math.min(99, base + Math.round(Math.random() * 4 - 2));
  const skillScore = Math.min(99, Math.max(40, base - 5 + skillBonus + Math.round(Math.random() * 4 - 2)));
  const signalScore = Math.min(99, Math.max(35, base - 8 + Math.round(Math.random() * 6 - 3)));
  return { semantic: semanticScore, skills: skillScore, signal: signalScore };
}

