// Parse reasoning string → structured fields
function parseReasoning(reasoning) {
  const titleMatch = reasoning.match(/^(.+?) with ([\d.]+) yrs/);
  const skillsMatch = reasoning.match(/(\d+) AI core skills/);
  const rateMatch = reasoning.match(/response rate ([\d.]+)/);
  return {
    title: titleMatch ? titleMatch[1] : 'ML Engineer',
    yoe: titleMatch ? parseFloat(titleMatch[2]) : 0,
    coreSkills: skillsMatch ? parseInt(skillsMatch[1]) : 0,
    responseRate: rateMatch ? parseFloat(rateMatch[1]) : 0,
  };
}

// Build full candidate objects for the UI
export const CANDIDATES = RAW_SUBMISSION.map((raw, idx) => {
  const parsed = parseReasoning(raw.reasoning);
  const scores = deriveScores(raw.score, parsed.coreSkills);
  const tag = getTag(raw.score);

  return {
    id: raw.candidate_id,
    name: raw.candidate_id, // Real ID as display name
    initials: getInitials(raw.rank, parsed.title),
    role: `${parsed.title}`,
    location: 'India',
    exp: `${parsed.yoe} yrs`,
    avatarVariant: AVATAR_VARIANTS[idx % AVATAR_VARIANTS.length],
    scores,
    rawScore: raw.score,
    rank: raw.rank,
    skills: getSkillsForTitle(parsed.title),
    summary: raw.reasoning,
    tag,
    coreSkillsCount: parsed.coreSkills,
    responseRate: parsed.responseRate,
  };
});

// Pre-computed stats for the proof bar
export const DATASET_STATS = {
  total: CANDIDATES.length,
  shortlisted: CANDIDATES.filter(c => c.tag === 'top' || c.tag === 'strong').length,
  avgScore: Math.round(CANDIDATES.reduce((a, c) => a + c.rawScore, 0) / CANDIDATES.length * 100),
  topScore: Math.round(CANDIDATES[0].rawScore * 100),
  topCandidate: CANDIDATES[0],
};

